/// [Apple's documentation](https://developer.apple.com/documentation/carbon/eventrecord?language=objc)
#[repr(C, packed(2))]
#[derive(Clone, Copy, Debug, PartialEq, Default)]
pub struct EventRecord {
    pub what: EventKind,
    pub message: c_ulong,
    pub when: u32,
    pub r#where: Point,
    pub modifiers: EventModifiers,
}

#[cfg(feature = "objc2")]
unsafe impl Encode for EventRecord {
    const ENCODING: Encoding = Encoding::Struct(
        "EventRecord",
        &[
            <EventKind>::ENCODING,
            Encoding::C_ULONG,
            <u32>::ENCODING,
            <Point>::ENCODING,
            <EventModifiers>::ENCODING,
        ],
    );
}

#[cfg(feature = "objc2")]
unsafe impl RefEncode for EventRecord {
    const ENCODING_REF: Encoding = Encoding::Pointer(&Self::ENCODING);
}

